@@ -0,0 +1,198 @@
+* {
+  margin: 0;
+  padding: 0;
+  box-sizing: border-box;
+}
+
+body {
+  background: #0a0a0a;
+  color: #e0e0e0;
+  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
+  min-height: 100vh;
+  padding: 32px 24px;
+  line-height: 1.7;
+}
+
+#app {
+  max-width: 760px;
+  margin: 0 auto;
+}
+
+header {
+  margin-bottom: 36px;
+  text-align: center;
+}
+
+h1 {
+  font-size: 1.6rem;
+  font-weight: 700;
+  margin-bottom: 8px;
+}
+
+h1 a {
+  color: inherit;
+  text-decoration: none;
+}
+
+h1 .dim {
+  color: #4fc3f7;
+  font-weight: 400;
+}
+
+.subtitle {
+  font-size: 0.85rem;
+  color: #888;
+  max-width: 560px;
+  margin: 0 auto 12px;
+}
+
+.subtitle code {
+  background: #1a1a1a;
+  padding: 1px 6px;
+  border-radius: 4px;
+  font-family: ui-monospace, SFMono-Regular, monospace;
+  font-size: 0.78rem;
+  color: #4fc3f7;
+}
+
+nav a {
+  color: #4fc3f7;
+  text-decoration: none;
+  font-size: 0.78rem;
+}
+
+nav a:hover {
+  text-decoration: underline;
+}
+
+section {
+  margin-bottom: 36px;
+}
+
+h2 {
+  font-size: 1.15rem;
+  font-weight: 700;
+  margin-bottom: 14px;
+  color: #fff;
+  padding-bottom: 8px;
+  border-bottom: 1px solid #1a1a1a;
+}
+
+h3 {
+  font-size: 0.95rem;
+  font-weight: 600;
+  margin: 18px 0 10px;
+  color: #ddd;
+}
+
+p {
+  font-size: 0.86rem;
+  color: #bbb;
+  margin-bottom: 12px;
+}
+
+ul {
+  margin-left: 20px;
+  margin-bottom: 12px;
+}
+
+li {
+  font-size: 0.86rem;
+  color: #bbb;
+  margin-bottom: 6px;
+}
+
+strong {
+  color: #fff;
+  font-weight: 600;
+}
+
+code {
+  background: #141414;
+  padding: 1px 6px;
+  border-radius: 4px;
+  font-family: ui-monospace, SFMono-Regular, monospace;
+  font-size: 0.78rem;
+  color: #4fc3f7;
+}
+
+a {
+  color: #4fc3f7;
+}
+
+table.cmp {
+  width: 100%;
+  border-collapse: collapse;
+  margin: 14px 0;
+  font-size: 0.82rem;
+}
+
+table.cmp th {
+  text-align: left;
+  font-weight: 600;
+  color: #888;
+  font-size: 0.74rem;
+  letter-spacing: 0.04em;
+  text-transform: uppercase;
+  padding: 8px 12px;
+  border-bottom: 1px solid #222;
+  background: #0d0d0d;
+}
+
+table.cmp td {
+  padding: 8px 12px;
+  border-bottom: 1px solid #161616;
+  font-family: ui-monospace, SFMono-Regular, monospace;
+  font-size: 0.82rem;
+  color: #ccc;
+}
+
+table.cmp td:first-child {
+  font-family: inherit;
+  color: #999;
+}
+
+table.cmp.small th,
+table.cmp.small td {
+  padding: 6px 10px;
+  font-size: 0.78rem;
+}
+
+table.cmp .win {
+  color: #66bb6a;
+  font-weight: 600;
+}
+
+table.cmp .note {
+  color: #888;
+  font-family: inherit;
+  font-style: italic;
+}
+
+footer {
+  text-align: center;
+  margin-top: 48px;
+  padding-top: 24px;
+  border-top: 1px solid #1a1a1a;
+  font-size: 0.78rem;
+  color: #555;
+}
+
+footer a {
+  color: #4fc3f7;
+  text-decoration: none;
+  margin: 0 6px;
+}
+
+footer a:hover {
+  text-decoration: underline;
+}
+
+@media (max-width: 600px) {
+  table.cmp {
+    font-size: 0.74rem;
+  }
+  table.cmp th, table.cmp td {
+    padding: 6px 8px;
+  }
+}

